  4→// 3 zones : Logo | Sections (6 tabs) | Actions (credits, notifs, profil)
  5→
  6→import React, { useState, useRef, useEffect } from 'react';
  7→import {
  8→  LayoutDashboard, ScanLine, Quote, Wrench, Store, Settings,
  9→  Zap, Bell, ChevronDown, LogOut, User as UserIcon,
 10→  CreditCard, Search, Menu, X
 11→} from 'lucide-react';
 12→import type { User } from '../../types';
 13→
 14→export type Section = 'dashboard' | 'analyse' | 'citations' | 'outils' | 'marketplace' | 'parametres';
 15→
 16→interface TopNavProps {
 17→  user: User | null;
 18→  activeSection: Section;
 19→  onSectionChange: (section: Section) => void;
 20→  animatedCredits: number;
 21→  onOpenCommandPalette: () => void;
 22→  onLogout: () => void;
 23→  onNavigate: (view: string) => void;
 24→}
 25→
 26→const SECTIONS: { id: Section; label: string; icon: React.ElementType }[] = [
 27→  { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard },
 28→  { id: 'analyse', label: 'Analyse', icon: ScanLine },
 29→  { id: 'citations', label: 'Citations', icon: Quote },
 30→  { id: 'outils', label: 'Outils', icon: Wrench },
 31→  { id: 'marketplace', label: 'Marketplace', icon: Store },
 32→  { id: 'parametres', label: 'Parametres', icon: Settings },
 33→];
 34→
 35→export default function TopNav({
 36→  user,
 37→  activeSection,
 38→  onSectionChange,
 39→  animatedCredits,
 40→  onOpenCommandPalette,
 41→  onLogout,
 42→  onNavigate,
 43→}: TopNavProps) {
 44→  const [isProfileOpen, setIsProfileOpen] = useState(false);
 45→  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
 46→  const profileRef = useRef<HTMLDivElement>(null);
 47→
 48→  useEffect(() => {
 49→    const handleClickOutside = (e: MouseEvent) => {
 50→      if (profileRef.current && !profileRef.current.contains(e.target as Node)) {
 51→        setIsProfileOpen(false);
 52→      }
 53→    };
 54→    if (isProfileOpen) document.addEventListener('mousedown', handleClickOutside);
 55→    return () => document.removeEventListener('mousedown', handleClickOutside);
 56→  }, [isProfileOpen]);
 57→
 58→  if (!user) return null;
 59→
 60→  return (
 61→    <header className="fixed top-0 left-0 right-0 z-50 h-14 bg-[#0A0A0F]/95 backdrop-blur-xl border-b border-white/[0.06]">
 62→      <div className="h-full max-w-[1800px] mx-auto px-4 flex items-center justify-between gap-4">
 63→
 64→        {/* ── Zone 1 : Logo ── */}
 65→        <button
 66→          onClick={() => onSectionChange('dashboard')}
 67→          className="flex items-center gap-2 shrink-0 group"
 68→        >
 69→          <div className="w-7 h-7 rounded-lg bg-gradient-to-br from-purple-500 to-violet-600 flex items-center justify-center shadow-lg shadow-purple-900/30 group-hover:shadow-purple-800/40 transition-shadow">
 70→            <span className="text-white font-bold text-xs">C</span>
 71→          </div>
 72→          <span className="text-white font-semibold text-sm hidden sm:block">
 73→            CitedBy<span className="text-purple-400">.ai</span>
 74→          </span>
 75→        </button>
 76→
 77→        {/* ── Zone 2 : Section Tabs (desktop) ── */}
 78→        <nav className="hidden md:flex items-center gap-1 bg-white/[0.03] rounded-xl px-1 py-1">
 79→          {SECTIONS.map(({ id, label, icon: Icon }) => {
 80→            const isActive = id === activeSection;
 81→            return (
 82→              <button
 83→                key={id}
 84→                onClick={() => onSectionChange(id)}
 85→                className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-medium transition-all duration-200
 86→                  ${isActive
 87→                    ? 'bg-white/[0.1] text-white shadow-sm'
 88→                    : 'text-slate-500 hover:text-slate-300 hover:bg-white/[0.04]'
 89→                  }`}
 90→              >
 91→                <Icon className="w-3.5 h-3.5" />
 92→                {label}
 93→              </button>
 94→            );
 95→          })}
 96→        </nav>
 97→
 98→        {/* ── Zone 3 : Actions ── */}
 99→        <div className="flex items-center gap-2">
100→          {/* Search shortcut */}
101→          <button
102→            onClick={onOpenCommandPalette}
103→            className="hidden sm:flex items-center gap-2 px-3 py-1.5 rounded-lg bg-white/[0.04] border border-white/[0.06] text-slate-500 hover:text-slate-300 hover:bg-white/[0.06] transition-all text-xs"
104→          >
105→            <Search className="w-3.5 h-3.5" />
106→            <span className="hidden lg:block">Rechercher...</span>
107→            <kbd className="hidden lg:block text-[10px] px-1.5 py-0.5 rounded bg-white/[0.06] border border-white/[0.08] text-slate-600 font-mono">
108→              Ctrl+K
109→            </kbd>
110→          </button>
111→
112→          {/* Credits */}
113→          <button
114→            onClick={() => onNavigate('recharge')}
115→            className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-white/[0.04] border border-white/[0.06] hover:bg-white/[0.06] transition-all"
116→          >
117→            <Zap className="w-3.5 h-3.5 text-purple-400" />
118→            <span className="text-xs font-medium text-white">{animatedCredits}</span>
119→            <span className="text-[10px] text-slate-600 hidden sm:block">credits</span>
120→          </button>
121→
122→          {/* Profile dropdown */}
123→          <div ref={profileRef} className="relative">
124→            <button
125→              onClick={() => setIsProfileOpen(!isProfileOpen)}
126→              className="flex items-center gap-2 px-2 py-1.5 rounded-lg hover:bg-white/[0.04] transition-all"
127→            >
128→              <div className="w-7 h-7 rounded-full bg-gradient-to-br from-purple-500/30 to-violet-500/30 border border-purple-500/20 flex items-center justify-center">
129→                <span className="text-[10px] font-bold text-purple-300">
130→                  {user.name?.charAt(0).toUpperCase() || 'U'}
131→                </span>
132→              </div>
133→              <ChevronDown className={`w-3 h-3 text-slate-500 transition-transform ${isProfileOpen ? 'rotate-180' : ''}`} />
134→            </button>
135→
136→            {isProfileOpen && (
137→              <div className="absolute right-0 top-full mt-2 w-56 rounded-xl bg-[#13131d] border border-white/[0.08] shadow-2xl shadow-black/50 overflow-hidden animate-in fade-in slide-in-from-top-2 duration-150 z-[60]">
138→                <div className="px-4 py-3 border-b border-white/[0.06]">
139→                  <p className="text-sm font-medium text-white truncate">{user.name}</p>
140→                  <p className="text-xs text-slate-500 truncate">{user.email}</p>
141→                </div>
142→                <div className="py-1">
143→                  <button
144→                    onClick={() => { onNavigate('account'); setIsProfileOpen(false); }}
145→                    className="w-full flex items-center gap-2.5 px-4 py-2.5 text-xs text-slate-400 hover:text-white hover:bg-white/[0.04] transition-colors"
146→                  >
147→                    <UserIcon className="w-3.5 h-3.5" />
148→                    Mon compte
149→                  </button>
150→                  <button
151→                    onClick={() => { onNavigate('recharge'); setIsProfileOpen(false); }}
152→                    className="w-full flex items-center gap-2.5 px-4 py-2.5 text-xs text-slate-400 hover:text-white hover:bg-white/[0.04] transition-colors"
153→                  >
154→                    <CreditCard className="w-3.5 h-3.5" />
155→                    Recharger
156→                  </button>
157→                </div>
158→                <div className="border-t border-white/[0.06] py-1">
159→                  <button
160→                    onClick={() => { onLogout(); setIsProfileOpen(false); }}
161→                    className="w-full flex items-center gap-2.5 px-4 py-2.5 text-xs text-red-400 hover:text-red-300 hover:bg-red-500/[0.06] transition-colors"
162→                  >
163→                    <LogOut className="w-3.5 h-3.5" />
164→                    Deconnexion
165→                  </button>
166→                </div>
167→              </div>
168→            )}
169→          </div>
170→
171→          {/* Mobile menu toggle */}
172→          <button
173→            onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
174→            className="md:hidden p-2 rounded-lg hover:bg-white/[0.04] transition-colors"
175→          >
176→            {isMobileMenuOpen ? (
177→              <X className="w-5 h-5 text-slate-400" />
178→            ) : (
179→              <Menu className="w-5 h-5 text-slate-400" />
180→            )}
181→          </button>
182→        </div>
183→      </div>
184→
185→      {/* ── Mobile Menu ── */}
186→      {isMobileMenuOpen && (
187→        <div className="md:hidden bg-[#0A0A0F] border-b border-white/[0.06] animate-in slide-in-from-top duration-200">
188→          <div className="px-4 py-3 grid grid-cols-3 gap-2">
189→            {SECTIONS.map(({ id, label, icon: Icon }) => {
190→              const isActive = id === activeSection;
191→              return (
192→                <button
193→                  key={id}
194→                  onClick={() => { onSectionChange(id); setIsMobileMenuOpen(false); }}
195→                  className={`flex flex-col items-center gap-1 py-2.5 rounded-xl text-[10px] font-medium transition-all
196→                    ${isActive
197→                      ? 'bg-purple-500/10 text-purple-400 border border-purple-500/20'
198→                      : 'text-slate-500 hover:text-slate-300 hover:bg-white/[0.03]'
199→                    }`}
200→                >
201→                  <Icon className="w-4 h-4" />
202→                  {label}
203→                </button>
204→              );
205→            })}
206→          </div>
207→        </div>
208→      )}
209→    </header>
210→  );
211→}
