163→interface AppSidebarProps {
164→  activeSection: Section;
165→  activePage: string;
166→  onNavigate: (view: string) => void;
167→  isCollapsed: boolean;
168→  onToggle: () => void;
169→}
170→
171→export default function AppSidebar({
172→  activeSection,
173→  activePage,
174→  onNavigate,
175→  isCollapsed,
176→}: AppSidebarProps) {
177→  const groups = getSidebarConfig(activeSection);
178→
179→  // Pas de sidebar pour dashboard (full-width)
180→  if (activeSection === 'dashboard' || groups.length === 0) return null;
181→
182→  return (
183→    <aside
184→      className={`hidden md:flex flex-col shrink-0 h-[calc(100vh-3.5rem)] sticky top-14 border-r border-white/[0.06] bg-[#0A0A0F]/50 overflow-y-auto custom-scrollbar transition-all duration-200
185→        ${isCollapsed ? 'w-16' : 'w-60'}`}
186→    >
187→      <div className="py-3 px-3 flex-1">
188→        {groups.map((group, gi) => (
189→          <div key={gi} className={gi > 0 ? 'mt-4 pt-4 border-t border-white/[0.04]' : ''}>
190→            {/* Group title */}
191→            {group.title && !isCollapsed && (
192→              <p className="px-2 mb-2 text-[10px] font-semibold uppercase tracking-wider text-slate-600">
193→                {group.title}
194→              </p>
195→            )}
196→
197→            {/* Items */}
198→            <div className="space-y-0.5">
199→              {group.items.map((item) => {
200→                const Icon = item.icon;
201→                const isActive = item.id === activePage;
202→
203→                return (
204→                  <button
205→                    key={item.id}
206→                    onClick={() => onNavigate(item.id)}
207→                    className={`w-full flex items-center gap-2.5 px-2.5 py-2 rounded-lg text-left transition-all duration-150 group
208→                      ${isActive
209→                        ? 'bg-white/[0.08] text-white'
210→                        : 'text-slate-500 hover:text-slate-300 hover:bg-white/[0.03]'
211→                      }
212→                      ${isCollapsed ? 'justify-center' : ''}
213→                    `}
214→                    title={isCollapsed ? item.label : undefined}
215→                  >
216→                    <Icon className={`w-4 h-4 shrink-0 ${isActive ? 'text-purple-400' : 'text-slate-600 group-hover:text-slate-400'}`} />
217→
218→                    {!isCollapsed && (
219→                      <div className="flex-1 min-w-0">
220→                        <div className="flex items-center gap-2">
221→                          <span className="text-xs font-medium truncate">{item.label}</span>
222→                          {item.badge && (
223→                            <span className={`text-[9px] px-1.5 py-0.5 rounded-full font-semibold ${item.badgeColor || 'bg-purple-500/20 text-purple-400'}`}>
224→                              {item.badge}
225→                            </span>
226→                          )}
227→                        </div>
228→                        {item.description && (
229→                          <p className="text-[10px] text-slate-600 truncate mt-0.5">
230→                            {item.description}
231→                          </p>
232→                        )}
233→                      </div>
234→                    )}
235→                  </button>
236→                );
237→              })}
238→            </div>
239→          </div>
240→        ))}
241→      </div>
242→    </aside>
243→  );
244→}
245→
246→// Export pour que App.tsx puisse determiner la section a partir d'une page
247→export function getSectionForPage(page: string): Section {
248→  const analysisPages = ['analyze', 'projects', 'results', 'history', 'ai-monitoring', 'alerts', 'bot-tracking', 'reputation'];
249→  const citationPages = ['citation-dashboard', 'tracked-queries', 'citation-detail', 'benchmark', 'monthly-report', 'calibration', 'v3-alerts', 'alert-settings'];
250→  const outilsPages = ['generative-tools', 'smc-studio', 'content-writer', 'blog-optimizer', 'source-of-truth', 'schema-org', 'robots-txt', 'llms-txt', 'ai-response-layer', 'ai-citation-simulator', 'answer-first-audit', 'eeat-builder'];
251→  const marketplacePages = ['directory', 'directory-entity', 'publisher-request', 'clients', 'affiliation', 'mission-orders', 'messages'];
252→  const parametresPages = ['account', 'recharge', 'integrations', 'api-developer'];
253→
254→  if (analysisPages.includes(page)) return 'analyse';
255→  if (citationPages.includes(page)) return 'citations';
256→  if (outilsPages.includes(page)) return 'outils';
257→  if (marketplacePages.includes(page)) return 'marketplace';
258→  if (parametresPages.includes(page)) return 'parametres';
259→  return 'dashboard';
260→}
